"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeRecurringCost — edit surface for a charge that repeats.
   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Finance/
   magellan-finance-recurring-cost.html

   "= Supplier edit + diff" (model spec §8.4). Edit-mode form (no drop zone —
   this is an existing record, style guide §15): the action segment
   (Change amount / Pause / Cancel / Renegotiated) drives which fields show and
   recomputes a live DIFF read (was→now, struck-through old, tinted new). The
   HERO is the ANNUAL impact (12× the monthly line) because that's what the
   change is really worth. It feeds the fixed-cost ratio and the cash forecast.

   Pattern (per Bridge style guide §3-6, §15):
   - Context bar = the existing charge (per month / per year / % of fixed costs)
   - Form card with the action segment + action-driven fields
   - Live "What this changes" diff read — provenance is firm/measured green
     because an existing record has real history
   - Commit bar: Cancel + a single primary "Save change →" with done-state
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import { RECURRING_COST_DATA } from "@/features/finance/api/finance-recurring-cost-data";
import type { RcAction, RcFrequency } from "@/features/finance/api/finance-recurring-cost-data";
import "./BridgeRecurringCost.css";

const fmtUSD = (v: number) => `$${Math.round(v).toLocaleString()}`;
const parseAmt = (s: string) =>
  parseFloat(s.replace(/[^0-9.]/g, "")) || 0;

export function BridgeRecurringCost() {
  const { setPage } = useBridge();
  const { charge, actions, frequencies, fixedCostsTotal } = RECURRING_COST_DATA;

  const [action, setAction] = useState<RcAction>("amount");
  const [amount, setAmount] = useState("");
  const [frequency, setFrequency] = useState<RcFrequency>(charge.frequency);
  const [effective, setEffective] = useState("");
  const [reason, setReason] = useState("");
  const [freqOpen, setFreqOpen] = useState(false);
  const [saved, setSaved] = useState(false);

  // Amount + frequency only matter for amount/renegotiation moves.
  const showAmount = action === "amount" || action === "renew";

  const read = useMemo(() => {
    const curMonth = charge.monthly;
    // Pause / cancel drop the line to $0; otherwise the typed amount (or current).
    const typed = parseAmt(amount);
    const newMonth =
      action === "pause" || action === "cancel"
        ? 0
        : typed > 0
          ? typed
          : curMonth;

    const wasYear = curMonth * 12;
    const newYear = newMonth * 12;

    // Annual impact: positive = saving, negative = increase. This is the hero.
    const delta = wasYear - newYear;

    // Fixed-cost ratio recomputes against the adjusted base.
    const newFixed = fixedCostsTotal - curMonth + newMonth;
    const newRatio = newFixed > 0 ? (newMonth / newFixed) * 100 : 0;

    return {
      curMonth,
      newMonth,
      wasYear,
      newYear,
      delta,
      monthChanged: newMonth !== curMonth,
      yearChanged: newYear !== wasYear,
      newRatio,
    };
  }, [action, amount, charge.monthly, fixedCostsTotal]);

  // Provenance chip copy — measured/firm green because the record has history.
  const provLabel = useMemo(() => {
    switch (action) {
      case "pause":
        return "Measured — pausing to $0";
      case "cancel":
        return "Measured — cancelling";
      default:
        return "Measured from the existing charge";
    }
  }, [action]);

  // The note + commit label react to the action (style guide §5).
  const note = useMemo(() => {
    switch (action) {
      case "pause":
        return (
          <>
            Pausing stops future charges without losing the record &mdash; Magellan keeps the cost in your books at $0 and reminds you when you might want to resume. Annualized, pausing frees up {fmtUSD(read.wasYear)} until you turn it back on.
          </>
        );
      case "cancel":
        return (
          <>
            Cancelling removes this charge from all future months. Past charges stay as recorded. Annualized, this takes {fmtUSD(read.wasYear)} off your fixed costs &mdash; the number that matters, not the {fmtUSD(read.curMonth)} monthly line.
          </>
        );
      case "renew":
        return (
          <>
            Recording a renegotiated rate updates every future charge from the effective date. Magellan shows the <b>annualized</b> difference so you can see what the negotiation actually won you across the year.
          </>
        );
      default:
        return (
          <>
            Editing a recurring cost updates every future charge, not just this month &mdash; so Magellan shows the <b>annualized</b> impact, which is usually 12&times; bigger than the monthly line suggests. The change takes effect from the date you set; past charges stay as recorded. Recurring costs feed your fixed-cost ratio and the cash forecast.
          </>
        );
    }
  }, [action, read.wasYear, read.curMonth]);

  const commitLabel = useMemo(() => {
    switch (action) {
      case "pause":
        return "Pause this charge →";
      case "cancel":
        return "Cancel this charge →";
      case "renew":
        return "Save renegotiated rate →";
      default:
        return "Save change →";
    }
  }, [action]);

  // Annual-impact hero: saving (−green), increase (+caution), or neutral.
  const impactClass =
    read.delta > 0 ? "good" : read.delta < 0 ? "alert" : "";
  const impactText =
    read.delta > 0
      ? `−${fmtUSD(read.delta)}`
      : read.delta < 0
        ? `+${fmtUSD(-read.delta)}`
        : "$0";

  const save = () => {
    setSaved(true);
    setTimeout(() => {
      setSaved(false);
      setPage("home");
    }, 1500);
  };

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M21 12 a9 9 0 1 1 -2.6 -6.4" />
            <path d="M21 4 v4 h-4" />
            <path d="M12 8 v4 l3 2" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Edit Recurring Cost</div>
          <div className="bridge-page-head-sub">
            Change a charge that repeats &mdash; pause it, cancel it, renegotiate the amount. Magellan shows the annualized impact, not just this month&rsquo;s line, so you see what the change is really worth.
          </div>
        </div>
      </div>

      {/* The existing charge — context bar */}
      <div className="bridge-rb-sku">
        <div className="bridge-rb-sku-main">
          <div className="bridge-rb-sku-name">{charge.name}</div>
          <div className="bridge-rb-sku-meta">{charge.meta}</div>
        </div>
        <div className="bridge-rb-sku-stats">
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{fmtUSD(read.curMonth)}</span>
            <span className="bridge-rb-stat-k">per month</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{fmtUSD(read.wasYear)}</span>
            <span className="bridge-rb-stat-k">per year</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">
              {((read.curMonth / fixedCostsTotal) * 100).toFixed(1)}%
            </span>
            <span className="bridge-rb-stat-k">of fixed costs</span>
          </div>
        </div>
      </div>

      {/* The change */}
      <div className="bridge-ni-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">The change</span>
          <span className="bridge-ni-source manual">&#9998; Editing an existing charge</span>
        </div>
        <div className="bridge-ni-grid">
          <div className="bridge-ni-field bridge-ni-span">
            <span className="bridge-ni-label">What to do</span>
            <div className="bridge-ni-seg">
              {actions.map((a) => (
                <button
                  key={a.id}
                  type="button"
                  className={action === a.id ? "on" : ""}
                  onClick={() => setAction(a.id)}
                >
                  {a.label}
                </button>
              ))}
            </div>
          </div>

          {showAmount && (
            <>
              <div className="bridge-ni-field">
                <span className="bridge-ni-label">New amount</span>
                <input
                  className="bridge-ni-input"
                  type="text"
                  placeholder={fmtUSD(charge.monthly)}
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                />
              </div>
              <div className="bridge-ni-field">
                <span className="bridge-ni-label">Frequency</span>
                <div
                  className={`bridge-ni-select${freqOpen ? " open" : ""}`}
                  onClick={() => setFreqOpen((o) => !o)}
                >
                  <span>{frequency}</span>
                  <span className="chev">&#9662;</span>
                  {freqOpen && (
                    <div className="bridge-ni-menu open">
                      {frequencies.map((f) => (
                        <div
                          key={f}
                          className="bridge-ni-menu-item"
                          onClick={(e) => {
                            e.stopPropagation();
                            setFrequency(f);
                            setFreqOpen(false);
                          }}
                        >
                          {f}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </>
          )}

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Effective from</span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder={charge.effectiveLabel}
              value={effective}
              onChange={(e) => setEffective(e.target.value)}
            />
          </div>
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">
              Reason
              <span className="bridge-ni-hint">optional &mdash; for the record</span>
            </span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder="e.g. downgraded plan, renegotiated rate"
              value={reason}
              onChange={(e) => setReason(e.target.value)}
            />
          </div>
        </div>
      </div>

      {/* What this changes — the diff read */}
      <div className="bridge-ni-outcome">
        <div className="bridge-ni-outcome-head">
          <span className="m-mark">M</span> What this changes
          <span className="bridge-ni-outcome-prov firm">{provLabel}</span>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">The change</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Per month</span>
              <span className="v">
                <span className={`bridge-erc-diff${read.monthChanged ? "" : " unchanged"}`}>
                  <span className="was">{fmtUSD(read.curMonth)}</span>
                  <span className="arr">&rarr;</span>
                  <span className={`now${read.monthChanged ? " good" : ""}`}>
                    {fmtUSD(read.newMonth)}
                  </span>
                </span>
              </span>
              <span className="kk">recurring line</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Per year</span>
              <span className="v">
                <span className={`bridge-erc-diff${read.yearChanged ? "" : " unchanged"}`}>
                  <span className="was">{fmtUSD(read.wasYear)}</span>
                  <span className="arr">&rarr;</span>
                  <span className={`now${read.yearChanged ? " good" : ""}`}>
                    {fmtUSD(read.newYear)}
                  </span>
                </span>
              </span>
              <span className="kk">annualized</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Annual impact</span>
              <span className={`bridge-erc-impact${impactClass ? ` ${impactClass}` : ""}`}>
                {impactText}
                {read.delta !== 0 && <small> /yr</small>}
              </span>
              <span className="kk">what the change is worth</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Fixed-cost ratio</span>
              <span className="v">{read.newRatio.toFixed(1)}%</span>
              <span className="kk">share of fixed costs</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-note">{note}</div>
      </div>

      {/* Commit */}
      <div className="bridge-ni-commit">
        <div className="bridge-ni-commit-note">
          This drafts the change &mdash; <b>future charges aren&rsquo;t altered</b> until you confirm. Reversible.
        </div>
        <div className="bridge-ni-commit-btns">
          <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
            Cancel
          </button>
          <button
            className={`bridge-ni-create${saved ? " done" : ""}`}
            type="button"
            onClick={save}
            disabled={saved}
          >
            {saved ? "✓ Change saved" : commitLabel}
          </button>
        </div>
      </div>
    </div>
  );
}
