/** The action the founder is taking on this recurring charge. */
export type RcAction = "amount" | "pause" | "cancel" | "renew";

/** One option in the "What to do" action segment. */
export interface RcActionOption {
  /** Stable key driving fields + read. */
  id: RcAction;
  /** Segment button label. */
  label: string;
}

/** A frequency option in the frequency dropdown. */
export type RcFrequency = "Monthly" | "Quarterly" | "Yearly";

/** The existing recurring charge being edited (the context bar). */
export interface RcCharge {
  /** Charge name headline (e.g. "Adobe Creative Cloud"). */
  name: string;
  /** Context-bar sub-line (category · cadence · history · next charge · provenance). */
  meta: string;
  /** Category classification. */
  category: string;
  /** Vendor / payee. */
  vendor: string;
  /** Current charge amount per period, USD. */
  monthly: number;
  /** Current billing cadence. */
  frequency: RcFrequency;
  /** Human label for when the change takes effect (next charge). */
  effectiveLabel: string;
}

/** Full surface payload. */
export interface RcData {
  charge: RcCharge;
  /** The action options for the segment, in display order. */
  actions: RcActionOption[];
  /** Frequency options for the dropdown. */
  frequencies: RcFrequency[];
  /** Total monthly fixed-cost base, USD — denominator for the fixed-cost ratio. */
  fixedCostsTotal: number;
}

